#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
  try {
    // Connect to the SQLite database
    auto conn = sqlgen::sqlite::Connection("test_db.sqlite");

    // Drop the table if it exists
    conn.drop_table_if_exists<Product>();

    // Create the Product table
    conn.create_table<Product>();

    // Begin a transaction for efficient batch insertion
    conn.execute("BEGIN TRANSACTION");

    try {
      // Insert all products in the transaction
      for (const auto& product : products) {
        conn.insert(product);
      }

      // Commit the transaction if all inserts succeed
      conn.execute("COMMIT");
      return true;
    } catch (...) {
      // Rollback the transaction on any error
      conn.execute("ROLLBACK");
      return false;
    }
  } catch (...) {
    // Return false if connection or table operations fail
    return false;
  }
}

}  // namespace batch_insert_products
```

This implementation:

1. **Connects** to the SQLite database "test_db.sqlite"
2. **Drops** the Product table if it exists using `drop_table_if_exists<Product>()`
3. **Creates** the Product table with the schema defined in the `Product` struct
4. **Begins a transaction** to ensure all inserts are atomic and efficient
5. **Inserts all products** within the transaction using a loop
6. **Commits the transaction** if all inserts succeed
7. **Rolls back** the transaction if any insert fails
8. **Returns** `true` on success, `false` on any error

The use of transactions ensures that either all products are inserted successfully or none are, maintaining data integrity. It also significantly improves performance for batch insertions by reducing disk I/O operations.

