    if (ids.empty()) {
        return true;
    }

    try {
        // Connect to SQLite database
        auto conn = sqlgen::sqlite::connect("test_db.sqlite");

        // Begin transaction for atomicity
        auto tx = conn.transaction();

        // Build SQL UPDATE query with IN clause
        std::ostringstream sql;
        sql << "UPDATE Document SET is_deleted = 1, deleted_at = CURRENT_TIMESTAMP WHERE doc_id IN (";

        // Create placeholders for each ID
