#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  try {
    // Connect to the SQLite database
    sqlgen::sqlite::Connection conn("test_db.sqlite");

    // Start a transaction
    conn.execute("BEGIN TRANSACTION");

    // Check if from_account has sufficient balance
    auto result = conn.query<Account>(
      "SELECT account_id, balance FROM Account WHERE account_id = ?",
      from_account_id
    );

    if (result.empty() || result[0].balance < amount) {
      conn.execute("ROLLBACK");
      return false;
    }

    // Update from_account: deduct amount
    int rows_affected = conn.execute(
      "UPDATE Account SET balance = balance - ? WHERE account_id = ? AND balance >= ?",
      amount, from_account_id, amount
    );

    if (rows_affected == 0) {
      conn.execute("ROLLBACK");
      return false;
    }

    // Update to_account: add amount
    rows_affected = conn.execute(
      "UPDATE Account SET balance = balance + ? WHERE account_id = ?",
      amount, to_account_id
    );

    if (rows_affected == 0) {
      conn.execute("ROLLBACK");
      return false;
    }

    // Commit the transaction
    conn.execute("COMMIT");
    return true;

  } catch (...) {
    // Any exception triggers rollback and returns failure
    return false;
  }
}

}
