# Complete Implementation

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace right_join_departments_projects {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string name;
};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  // Connect to SQLite database
  sqlgen::sqlite::Database db("test_db.sqlite");

  // Note: SQLite doesn't support RIGHT JOIN natively
  // RIGHT JOIN to include all departments is simulated as:
  // Department LEFT JOIN Project
  // However, based on the struct (project_name is not optional),
  // we perform: Project LEFT JOIN Department to include all projects

  std::vector<DepProj> results;

  // Execute raw SQL query since we need a RIGHT JOIN pattern
  // In SQLite, we swap tables and use LEFT JOIN
  auto query = db.query(R"(
    SELECT d.name, p.name 
    FROM Department d 
    LEFT JOIN Project p ON d.department_id = p.department_id
  )");

  auto rows = query.execute();

  for (const auto& row : rows) {
    DepProj dp;
    // Department name is always present in LEFT JOIN from Department
    dp.department_name = row.template get<std::string>(0);
    // Project name might be NULL if department has no projects
    if (!row.is_null(1)) {
      dp.project_name = row.template get<std::string>(1);
    } else {
      dp.project_name = "";  // Default empty string for non-optional field
    }
    results.push_back(dp);
  }

  return results;
}

}  // namespace right_join_departments_projects
```

