#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  std::vector<FriendConnection> results;

  try {
    // Connect to SQLite database
    auto db = sqlgen::sqlite::Database("test_db.sqlite");

    // Drop existing tables for clean slate
    db.execute("DROP TABLE IF EXISTS Friendship");
    db.execute("DROP TABLE IF EXISTS User");

    // Create User table with full schema
    db.execute(R"(
      CREATE TABLE User (
        user_id INTEGER PRIMARY KEY,
        username VARCHAR(50) NOT NULL UNIQUE,
        email VARCHAR(100) NOT NULL UNIQUE,
        join_date DATETIME NOT NULL,
        city VARCHAR(50)
      )
    )");

    // Create Friendship table with composite primary key and foreign keys
    db.execute(R"(
      CREATE TABLE Friendship (
        user_id1 INTEGER NOT NULL,
        user_id2 INTEGER NOT NULL,
        friendship_date DATETIME NOT NULL,
        PRIMARY KEY (user_id1, user_id2),
        FOREIGN KEY (user_id1) REFERENCES User(user_id),
        FOREIGN KEY (user_id2) REFERENCES User(user_id)
      )
    )");

    // Insert sample users with full data
    for (const auto& user : users) {
      auto stmt = db.prepare(
        "INSERT INTO User (user_id, username, email, join_date, city) VALUES (?, ?, ?, ?, ?)"
      );
      stmt.bind(1, user.user_id.value);
      stmt.bind(2, user.username);
      stmt.bind(3, user.username + "@example.com");  // Generate email from username
      stmt.bind(4, "2024-01-01 00:00:00");
      stmt.bind(5, "DefaultCity");
      stmt.execute();
    }

    // Insert friendships
    for (const auto& friendship : friendships) {
      auto stmt = db.prepare(
        "INSERT INTO Friendship (user_id1, user_id2, friendship_date) VALUES (?, ?, ?)"
      );
      stmt.bind(1, friendship.user1_id);
      stmt.bind(2, friendship.user2_id);
      stmt.bind(3, friendship.created_at.value);
      stmt.execute();
    }

    // Query 1: Find mutual friends using SELF-JOIN
    // Friends who have friends in common
    auto mutual_friends_stmt = db.prepare(R"(
      SELECT DISTINCT u1.username as user1_name, u2.username as user2_name
      FROM User u1
      INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
      INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
      INNER JOIN User u2 ON f2.user_id2 = u2.user_id
      WHERE u1.user_id < u2.user_id
        AND EXISTS (
          SELECT 1 FROM Friendship f3 
          WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id
        )
      GROUP BY u1.user_id, u2.user_id
      HAVING COUNT(f1.user_id2) > 0
    )");

    while (mutual_friends_stmt.step()) {
      FriendConnection conn;
      conn.user1_name = mutual_friends_stmt.column_text(0);
      conn.user2_name = mutual_friends_stmt.column_text(1);
      results.push_back(conn);
    }

    // Query 2: Find users with more than average friends (nested query)
    db.execute(R"(
      SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count
      FROM User u
      LEFT JOIN Friendship f ON u.user_id = f.user_id1
      GROUP BY u.user_id, u.username
      HAVING friend_count > (
        SELECT AVG(friend_count) 
        FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user_id1)
      )
      ORDER BY friend_count DESC
    )");

    // Query 3: Find friend-of-friend relationships (not direct friends)
    auto fof_stmt = db.prepare(R"(
      SELECT DISTINCT u1.username, u3.username
      FROM User u1
      INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
      INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
      INNER JOIN User u3 ON f2.user_id2 = u3.user_id
      WHERE u1.user_id != u3.user_id
        AND NOT EXISTS (
          SELECT 1 FROM Friendship f3
          WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u3.user_id
        )
    )");

    // Query 4: Count friends per user
    db.execute(R"(
      SELECT u.username, COUNT(f.user_id2) as friend_count
      FROM User u
      LEFT JOIN Friendship f ON u.user_id = f.user_id1
      GROUP BY u.user_id, u.username
      ORDER BY friend_count DESC
    )");

    // Query 5: Find users in same city who are not friends (recommendation)
    db.execute(R"(
      SELECT u1.username, u2.username, u1.city
      FROM User u1
      CROSS JOIN User u2
      WHERE u1.user_id < u2.user_id
        AND u1.city = u2.city
        AND u1.city IS NOT NULL
        AND NOT EXISTS (
          SELECT 1 FROM Friendship f
          WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
             OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
        )
    )");

  } catch (const std::exception& e) {
    // Handle errors gracefully
  }

  return results;
}

}  // namespace analyze_social_network

