std::vector<ValidatedProfile> trim_and_length_validation() {
  // Connect to the SQLite database
  sqlgen::sqlite::Database db("test_db.sqlite");

  // Execute query using trim (ltrim + rtrim) and length functions
  // TRIM removes leading and trailing whitespace (combines LTRIM and RTRIM)
  // LENGTH calculates the number of characters in the trimmed string
  auto results = db.query<ValidatedProfile>(R"(
