  std::string display_name;
  std::optional<std::string> bio;
  std::optional<std::string> avatar_url;
};

struct Result {
  int profile_id;
  std::string display_name;
};

std::vector<Result> column_is_null_checks() {
  // Connect to SQLite database
  auto db = sqlgen::sqlite::open("test_db.sqlite");

  // Define the Profile table
  auto profile_table = sqlgen::define_table<Profile>("Profile");

  // Query profiles where bio IS NULL or avatar_url IS NULL
  std::vector<Result> results;

  auto query = sqlgen::select(profile_table.profile_id, profile_table.display_name)
    .from(profile_table)
    .where(profile_table.bio.is_null() || profile_table.avatar_url.is_null());

  for (auto row : db.execute(query)) {
