      result.department_name = results.get<std::string>(0);
      result.first_name = results.get<std::string>(1);
      result.last_name = results.get<std::string>(2);
      result.salary = results.get<double>(3);
      analysis.inner_join_results.push_back(result);
    }
  }

  // 2. LEFT JOIN: Include all employees (even without departments)
  {
    auto stmt = db.prepare(R"(
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Employee e
      LEFT JOIN Department d ON e.department_id = d.department_id
    )");

    auto results = stmt.execute();
    while (results.next()) {
      JoinResult result;
      if (!results.is_null(0)) {
        result.department_name = results.get<std::string>(0);
      }
      result.first_name = results.get<std::string>(1);
      result.last_name = results.get<std::string>(2);
      result.salary = results.get<double>(3);
      analysis.left_join_results.push_back(result);
    }
  }

  // 3. RIGHT JOIN: Include all departments (even without employees)
  // SQLite doesn't support RIGHT JOIN natively, simulate with LEFT JOIN
  {
    auto stmt = db.prepare(R"(
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Department d
      LEFT JOIN Employee e ON d.department_id = e.department_id
    )");

