      }
      if (!results.is_null(3)) {
        result.salary = results.get<double>(3);
      }
      analysis.right_join_results.push_back(result);
    }
  }

  // 4. FULL JOIN: Include all employees and departments
  // SQLite doesn't support FULL JOIN, use UNION of LEFT and RIGHT joins
  {
    auto stmt = db.prepare(R"(
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Employee e
      LEFT JOIN Department d ON e.department_id = d.department_id
      UNION
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Department d
      LEFT JOIN Employee e ON d.department_id = e.department_id
    )");

    auto results = stmt.execute();
    while (results.next()) {
